INSERT INTO selection_items (id, slug, type, category, title, label, price_text, affiliate_text, reason, fit_for, notice, image_url, rating_text, review_count_text, is_highlighted, external_url, status, sort_order) VALUES
    ('c0000000-0000-0000-0000-000000000001', 'downy-odor',          'product', '세탁/침구',   '다우니 오도 프로텍트 부스터', '세탁 냄새', '12,900원대',       '쿠팡',       '운동복과 수건 냄새 관리에 쓰는 세탁 향 부스터',                         '세탁 후에도 냄새가 남는 수건이나 운동복 관리',          '가격은 예시이며 최종 가격은 판매 페이지에서 확인하세요.',          '/cleanloop/images/downy.jpg',       '4.8', '후기 2,184개', TRUE,  NULL, 'published', 1),
    ('c0000000-0000-0000-0000-000000000002', 'downy-light',         'product', '세탁/침구',   '다우니 라이트 오션 미스트',   '가벼운 향', '18,900원대',       '네이버쇼핑', '향이 과하지 않은 타입의 세탁 향 부스터 2개 구성',                       '강한 향보다 가벼운 세탁 향을 선호할 때',                '가격은 예시이며 최종 가격은 판매 페이지에서 확인하세요.',          '/cleanloop/images/laundry.jpeg',    '4.7', '후기 1,063개', FALSE, NULL, 'published', 2),
    ('c0000000-0000-0000-0000-000000000003', 'laundrego-bedding',   'service', '세탁/침구',   '런드리고 침구 수거',          '수거 배송', '이불 16,000원대',   '런드리고',   '부피 큰 침구를 문앞에서 수거하고 다시 배송하는 서비스',                  '집 세탁기로 이불 세탁이 부담스럽거나 건조 공간이 부족할 때', '가격과 가능 지역은 외부 페이지에서 최종 확인하세요.',             NULL,                              '4.7', '후기 2,051개', TRUE,  NULL, 'published', 3),
    ('c0000000-0000-0000-0000-000000000004', 'today-pickup',        'service', '쓰레기/수거', '오늘수거 정기 수거',          '정기 수거', '월 9,900원부터',    '오늘수거',   '주 1~2회 문앞 수거로 배출 요일을 놓치지 않게 돕는 서비스',               '퇴근 시간이 늦어 쓰레기 배출이 자주 밀릴 때',            '가격과 가능 지역은 외부 페이지에서 최종 확인하세요.',             NULL,                              '4.9', '후기 3,105개', FALSE, NULL, 'published', 4),
    ('c0000000-0000-0000-0000-000000000005', 'miso-aircon',         'service', '계절/가전',   '미소 에어컨 청소',            '방문 예약', '79,000원대부터',    '미소',       '송풍팬과 열교환기까지 분해 청소를 예약하는 방문 서비스',                  '냄새가 심하거나 냉방 시즌 전에 깊게 청소하고 싶을 때',    '가격과 가능 지역은 외부 페이지에서 최종 확인하세요.',             NULL,                              '4.7', '후기 2,312개', TRUE,  NULL, 'published', 5),
    ('c0000000-0000-0000-0000-000000000006', 'bath-squeegee',       'product', '욕실',        '욕실 스퀴지 세트',            '물기 제거', '8,900원대',        '네이버쇼핑', '샤워 후 벽면과 거울 물기를 빠르게 밀어내는 기본 도구',                   '물때가 자주 생기는 욕실에서 세제를 줄이고 싶을 때',       '가격은 예시이며 최종 가격은 판매 페이지에서 확인하세요.',          NULL,                              '4.6', '후기 924개',   FALSE, NULL, 'published', 6),
    ('c0000000-0000-0000-0000-000000000007', 'kitchen-drain-net',   'product', '주방',        '싱크대 배수구 거름망',         '배수구',   '6,500원대',        '쿠팡',       '음식물 찌꺼기와 냄새 관리를 쉽게 만드는 교체형 소모품',                  '배수구 청소가 자주 부담스럽고 냄새가 빨리 올라올 때',     '가격은 예시이며 최종 가격은 판매 페이지에서 확인하세요.',          NULL,                              '4.7', '후기 1,420개', FALSE, NULL, 'published', 7),
    ('c0000000-0000-0000-0000-000000000008', 'floor-roller',        'product', '바닥/먼지',   '리필형 롤클리너',             '머리카락', '9,900원대',        '오늘의집',   '머리카락과 큰 먼지를 물걸레 전 먼저 걷어내는 도구',                      '바닥 청소 전에 머리카락이 자주 밀릴 때',                 '가격은 예시이며 최종 가격은 판매 페이지에서 확인하세요.',          NULL,                              '4.8', '후기 3,018개', FALSE, NULL, 'published', 8),
    ('c0000000-0000-0000-0000-000000000009', 'supplies-refill-kit', 'product', '소모품',      '청소 소모품 리필 체크 키트',   '리필 체크', '15,900원대',       '마켓컬리',   '종량제 봉투, 장갑, 리필포처럼 자주 떨어지는 물건을 묶어 확인하는 구성',    '청소하려고 할 때 소모품이 없어 자주 멈출 때',            '가격은 예시이며 최종 가격은 판매 페이지에서 확인하세요.',          NULL,                              '4.5', '후기 612개',   FALSE, NULL, 'published', 9);
