INSERT INTO community_posts (id, type, title, tag, body, helpful_count, comments_count, answers_count, saved_count, status, is_recommended, created_at) VALUES
    ('e0000000-0000-0000-0000-000000000001', 'tips', '욕실 물때는 세제보다 물기 제거가 먼저입니다',           '욕실', '샤워 후 벽면과 거울의 물기를 바로 제거하면 물때가 쌓이는 속도가 확실히 느려집니다.',                   128, 2, 0, 64, 'published', TRUE,  DATEADD('DAY', -5,  CURRENT_TIMESTAMP)),
    ('e0000000-0000-0000-0000-000000000002', 'tips', '음식물 쓰레기는 탈취보다 배출 주기가 먼저입니다',       '수거', '여름에는 탈취제를 추가하는 것보다 배출 간격을 줄이는 쪽이 냄새 재발을 줄이는 데 효과적입니다.',        104, 2, 0, 43, 'published', FALSE, DATEADD('DAY', -9,  CURRENT_TIMESTAMP)),
    ('e0000000-0000-0000-0000-000000000003', 'tips', '수건 냄새는 세탁조와 건조 시간을 같이 봅니다',          '세탁', '향 제품을 더 넣기 전에 세탁조, 고무패킹, 건조 시간을 차례대로 보면 원인을 좁히기 쉽습니다.',           118, 2, 0, 58, 'published', FALSE, DATEADD('DAY', -3,  CURRENT_TIMESTAMP)),
    ('e0000000-0000-0000-0000-000000000004', 'tips', '물걸레 전 롤클리너 한 번이면 바닥 청소가 줄어듭니다',    '바닥', '머리카락과 큰 먼지를 먼저 걷어내면 물걸레가 밀리지 않고 바닥 자국도 덜 남습니다.',                    91,  2, 0, 38, 'published', FALSE, DATEADD('DAY', -12, CURRENT_TIMESTAMP)),
    ('e0000000-0000-0000-0000-000000000005', 'qa',   '대리석 세면대에 물때 제거제를 써도 되나요?',            '욕실', '산성 세제는 대리석 표면을 상하게 할 수 있습니다. 전용 세제 또는 중성세제를 먼저 확인하세요.',          88,  0, 2, 22, 'published', FALSE, DATEADD('DAY', -7,  CURRENT_TIMESTAMP)),
    ('e0000000-0000-0000-0000-000000000006', 'qa',   '수건 냄새가 세탁 후에도 남으면 뭘 먼저 봐야 하나요?',   '세탁', '세탁조, 고무패킹, 건조 시간을 차례대로 확인해보라는 답변이 가장 많이 도움을 받았습니다.',             81,  0, 2, 29, 'published', FALSE, DATEADD('DAY', -15, CURRENT_TIMESTAMP)),
    ('e0000000-0000-0000-0000-000000000007', 'qa',   '분리수거함은 몇 칸짜리가 현실적으로 좋나요?',         '수거', '3칸 이상은 오히려 안 쓰게 된다는 답변이 많았습니다.',                                                40,  0, 0, 9,  'published', FALSE, DATEADD('DAY', -20, CURRENT_TIMESTAMP));
