    ('f0000000-0000-0000-0000-000000000006', 'e0000000-0000-0000-0000-000000000003', 'a0000000-0000-0000-0000-000000000001', '향 부스터는 원인 확인 후 보조로 쓰는 편이 좋습니다.',                DATEADD('DAY', -1,  CURRENT_TIMESTAMP)),
    ('f0000000-0000-0000-0000-000000000007', 'e0000000-0000-0000-0000-000000000004', 'a0000000-0000-0000-0000-000000000001', '강한 접착 롤러는 일부 러그나 매트에 붙을 수 있습니다.',              DATEADD('DAY', -11, CURRENT_TIMESTAMP)),
    ('f0000000-0000-0000-0000-000000000008', 'e0000000-0000-0000-0000-000000000004', 'a0000000-0000-0000-0000-000000000001', '마루는 물걸레 물기를 많이 짜서 쓰는 편이 안전합니다.',              DATEADD('DAY', -10, CURRENT_TIMESTAMP)),
    ('f0000000-0000-0000-0000-000000000009', 'e0000000-0000-0000-0000-000000000005', 'a0000000-0000-0000-0000-000000000001', '대리석에는 산성 세제를 피하는 편이 안전합니다.',                     DATEADD('DAY', -6,  CURRENT_TIMESTAMP)),
    ('f0000000-0000-0000-0000-000000000010', 'e0000000-0000-0000-0000-000000000005', 'a0000000-0000-0000-0000-000000000001', '연마제가 든 제품도 광택을 해칠 수 있습니다.',                        DATEADD('DAY', -5,  CURRENT_TIMESTAMP)),
